  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 96 ORDER BY created_at DESC LIMIT 1), 'reading', 5, '다음은 무엇에 대한 글인지 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-96/reading/q5.png', NULL, NULL, '["장갑","이불","화장품","손수건"]'::jsonb, 2, '이불', NULL),
